    private fun ASTNode.isPartOfSingleLineFunctionLiteralWithParameters(): Boolean {
        require(elementType == BLOCK)
        val functionLiteral = treeParent.takeIf { it.elementType == FUNCTION_LITERAL } ?: return false

        // Check if the function literal has parameters
        val valueParameterList = functionLiteral.findChildByType(VALUE_PARAMETER_LIST) ?: return false

        // Check if there's an arrow (which separates parameters from body)
        val arrow = functionLiteral.findChildByType(ARROW) ?: return false

        // Check that there's no newline before the arrow (parameters are on single line)
        val lbrace = getStartOfBlock()?.takeIf { it.elementType == LBRACE } ?: return false
        return noNewLineInClosedRange(lbrace, arrow)
    }

    private companion object {
        private val LTOKEN_SET = TokenSet.create(LPAR, LBRACE, LBRACKET, LT)
        private val RTOKEN_SET = TokenSet.create(RPAR, RBRACE, RBRACKET, GT)
        private val MATCHING_RTOKEN_MAP =
            LTOKEN_SET.types.zip(
                RTOKEN_SET.types,
            ).toMap()
    }
