import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Test for lambda wrapping issue where single-line lambdas with parameters
 * should not be forced to wrap.
 */
class LambdaWrappingIssueTest {
    private val wrappingRuleAssertThat = assertThatRule { WrappingRule() }

    @Test
    fun `Given a single-line lambda with parameter that does not exceed max line length`() {
        val code =
            """
            val foo = { size -> icon?.getBitmap(size)?.await() }
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a single-line lambda with parameter on one line should keep it unchanged`() {
        val code =
            """
            val x = { a -> someFunction(a) }
            val y = { size -> icon?.getBitmap(size)?.await() }
            val z = { p -> doSomething(p) }
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a multiline lambda with parameter on separate line should keep special formatting`() {
        val code =
            """
            val foo = {
                    a,
                    b,
                    c ->
                doSomething()
            }
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a lambda with parameter where body is on multiple lines`() {
        val code =
            """
            val foo = { size ->
                val bitmap = icon?.getBitmap(size)
                bitmap?.await()
            }
            """.trimIndent()
        wrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a lambda without parameters should wrap if needed`() {
        val code =
            """
            val foo = { doSomething(); doSomethingElse() }
            """.trimIndent()
        val formattedCode =
            """
            val foo = {
                doSomething(); doSomethingElse()
            }
            """.trimIndent()
        wrappingRuleAssertThat(code)
            .hasLintViolation(1, 12, "Missing newline after \"{\"")
            .isFormattedAs(formattedCode)
    }
}
"}

